   return(
    <>
        <div className="Content-area ">
            <div className="poster"> <img src={poster}></img></div>
            <section key="1" id="top_new"> <HotNew/> </section>
            <section key={key} id="arrivals"> <Arr/> </section>
        </div>
    </>
   )
}
